    public Object parseWsOrder(Object order, Object... optionalArgs)
    {
        //
        //    {
        //        "id": "1894876776091648",
        //        "id_str": "1894876776091648",
        //        "order_type": 0,
        //        "order_subtype": 0,
        //        "datetime": "1751451375",
        //        "microtimestamp": "1751451375070000",
        //        "amount": 1.1,
        //        "amount_str": "1.10000000",
        //        "amount_traded": "0",
        //        "amount_at_create": "1.10000000",
        //        "price": 10.23,
        //        "price_str": "10.23",
        //        "is_liquidation": false,
        //        "trade_account_id": 0
        //    }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object id = this.safeString(order, "id_str");
        Object orderTypeRaw = this.safeStringLower(order, "order_type");
        Object side = ((Helpers.isTrue((Helpers.isEqual(orderTypeRaw, "1"))))) ? "sell" : "buy";
        Object orderSubTypeRaw = this.safeStringLower(order, "order_subtype"); // https://www.bitstamp.net/websocket/v2/#:~:text=order_subtype
        Object orderType = null;
        Object timeInForce = null;
        if (Helpers.isTrue(Helpers.isEqual(orderSubTypeRaw, "0")))
        {
            orderType = "limit";
        } else if (Helpers.isTrue(Helpers.isEqual(orderSubTypeRaw, "2")))
        {
            orderType = "market";
        } else if (Helpers.isTrue(Helpers.isEqual(orderSubTypeRaw, "4")))
        {
            orderType = "limit";
            timeInForce = "IOC";
        } else if (Helpers.isTrue(Helpers.isEqual(orderSubTypeRaw, "6")))
        {
            orderType = "limit";
            timeInForce = "FOK";
        } else if (Helpers.isTrue(Helpers.isEqual(orderSubTypeRaw, "8")))
        {
            orderType = "limit";
            timeInForce = "GTD";
        }
        Object price = this.safeString(order, "price_str");
        Object amount = this.safeString(order, "amount_str");
        Object filled = this.safeString(order, "amount_traded");
        Object eventVar = this.safeString(order, "event");
        Object status = null;
        if (Helpers.isTrue(Precise.stringEq(filled, amount)))
        {
            status = "closed";
        } else if (Helpers.isTrue(Helpers.isEqual(eventVar, "order_deleted")))
        {
            status = "canceled";
        }
        Object timestamp = this.safeTimestamp(order, "datetime");
        market = this.safeMarket(null, market);
        Object symbol = Helpers.GetValue(market, "symbol");
        final Object finalOrderType = orderType;
        final Object finalTimeInForce = timeInForce;
        final Object finalStatus = status;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "info", order );
            put( "symbol", symbol );
            put( "id", id );
            put( "clientOrderId", null );
            put( "timestamp", timestamp );
            put( "datetime", BitstampCore.this.iso8601(timestamp) );
            put( "lastTradeTimestamp", null );
            put( "type", finalOrderType );
            put( "timeInForce", finalTimeInForce );
            put( "postOnly", null );
            put( "side", side );
            put( "price", price );
            put( "stopPrice", null );
            put( "triggerPrice", null );
            put( "amount", amount );
            put( "cost", null );
            put( "average", null );
            put( "filled", filled );
            put( "remaining", null );
            put( "status", finalStatus );
            put( "fee", null );
            put( "trades", null );
        }}, market);
    }

